import { ResetHighlightItem } from '../../../../legend/events/visual-effects/size-slider/reset-highlight-item';
import { hideCursor } from '../../../../legend/events/visual-effects/size-slider/hide-cursor';
import { hideTooltip } from '../../../../legend/events/visual-effects/size-slider/hide-tooltip';
import { isEmptyObject } from '../../../../utils/zcutils';
import { getManagerID } from '../../../../events/reverse-legend-highlight';

export function HideHighlight(behaviourEventInstance, selectionManager) {
    let chart = this.chart,
        legendEvents = chart.legendEvents,
        legendEventManager = legendEvents && legendEvents.eventManager,
        id = behaviourEventInstance.instance.options.component.spec.id,
        manager = legendEventManager && legendEventManager[getManagerID(chart, id)],
        options = manager && manager.options;

    if (isEmptyObject(manager) || !options.enabled) {
        return;
    }

    ResetHighlightItem.call(manager, null, null, true);
    hideCursor.call(manager);
    hideTooltip.call(manager);
}
